var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>그라운드 원 시민 여러분께 안내 말씀드립니다.</color>","JPN":"<color=#ffd34c>グラウンド・ワンの市民の皆さんにご案内します。</color>","ENG":"<color=#ffd34c>Attention all Ground One citizens.</color>","TWN":"<color=#ffd34c>通知G1的市民。</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>현재, 연쇄적 현실 붕괴 현상의 진행이 둔화되면서 대균열에 출몰한 괴생명체가 물러나기 시작했습니다.</color>","JPN":"<color=#ffd34c>ただいま、連鎖的な現実崩壊現象の進行が鈍化し、大亀裂に出没した怪生命体が退却しはじめました。</color>","ENG":"<color=#ffd34c>The chain of reality collapses have started to slow down, and the mysterious creature that appeared in the Grand Dimension Crevice has begun to retreat.</color>","TWN":"<color=#ffd34c>目前連鎖現實崩壞現象已經趨緩下來，在大峽谷出沒的怪物開始撤退。</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>각 태스크포스는 전투 태세를 유지한 상태로 지시를 기다려 주시기 바랍니다.</color>","JPN":"<color=#ffd34c>各タスクフォースは戦闘態勢を維持したまま、指示をお待ちください。</color>","ENG":"<color=#ffd34c>To all TASKFORCEs, please maintain battle positions until further notice.</color>","TWN":"<color=#ffd34c>請各個特遣勢力維持戰鬥狀態，等候進一步指示。</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>반복합니다. 현재, 연쇄적 현실 붕괴 현상의 진행이 둔화되었으며……</color>","JPN":"<color=#ffd34c>繰り返します。ただいま、連鎖的な現実崩壊現象の進行が鈍化し……</color>","ENG":"<color=#ffd34c>I repeat, the chain of reality collapses have started to slow down...</color>","TWN":"<color=#ffd34c>再重複一次。目前連鎖現實崩壞現象已經趨緩下來……</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"오셨습니까, 단장님.","JPN":"お帰りなさい、団長。","ENG":"You're here, Captain.","TWN":"你來了，團長。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"기사단은 전원 전투 태세로 대기 중입니다.","JPN":"騎士団は全員戦闘態勢で待機しております。","ENG":"The order is on standby, ready to fight.","TWN":"騎士團全員已經進入作戰狀態。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"수고했다, 부단장. 지휘는 내가 맡을 테니 잠시 쉬도록.","JPN":"ご苦労だった、副団長。指揮は私が執ろう。君はしばらく休め。","ENG":"Good work, Deputy. I'll take the lead from now, go and get some rest.","TWN":"辛苦了，副團長。我來指揮，你休息一會兒。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"아닙니다. 단장님께서도 회의장 경호 지원으로 고생하셨을 테니까요.","JPN":"いいえ。団長も会議場の警護の支援でお疲れでしょうから。","ENG":"No. You must have had a long day yourself, from supporting the conference room security.","TWN":"沒關係，團長支援會場的警戒工作也很辛苦。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그런데 오늘은 평소와 다르군요. 대균열에 이변이 생겼는데도 회의를 속행하다니.","JPN":"しかし、今日はいつもとは違いましたね。大亀裂の異変が起きている最中にも関わらず、会議を続行するなんて。","ENG":"Today is quite different from the usual ones, though. They're proceeding with the meeting, even with disturbance in the Grand Dimension Crevice.","TWN":"不過大峽谷發生了這樣的異變，居然還在繼續開會，似乎和以前有些不太一樣？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"관리국에서 언질은 없었습니까?","JPN":"管理局から何か言われませんでしたか？","ENG":"Any news from the Administration?","TWN":"管理局沒說什麼嗎？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"오늘 중으로 회의가 끝날지도 미지수야. 관계자들도 당황한 기색이더군.","JPN":"今日中に会議が終わるかどうかもわからない。関係者たちも焦っている様子だった。","ENG":"I'm not even sure if the meeting is going to end today. The authorities looked pretty confused as well.","TWN":"今天之內會議能否結束還是個未知數。當局的態度看起來似乎也很不明確。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"관리국 직할 도시를 담당하는 최고 관리자들이 모두 출석했다고 들었습니다만…….","JPN":"管理局直轄都市を司る最高管理者たちが揃って出席したと聞いたのですが……","ENG":"I heard that every Supreme Administrator in charge of the Administration Direct Control Cities attended...","TWN":"聽說負責管理局直轄市的最高管理階層全都出席了……"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"오늘 안건은 상당히 중요한 사안인가 보군요.","JPN":"今日の案件はそれほど重要なものなんですね。","ENG":"Today's meeting must have been about something important indeed.","TWN":"看來今天的會議相當重要……"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"……그렇겠지. 아마도.","JPN":"……ああ。おそらくな。","ENG":"...Yes. Perhaps.","TWN":"……大概，是吧。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"안색이 좋지 않아 보입니다, 단장님.","JPN":"顔色が良くありませんね、団長。","ENG":"You don't look very well, Captain.","TWN":"你的臉色不太好，團長。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그런가? 다른 단원들 앞에서는 주의해야겠군.","JPN":"そうか？　他の団員の前では注意しないとな。","ENG":"Is that so? I should be careful in front of the other members.","TWN":"是嗎？在其他團員面前要小心了呢。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"버밍엄 교수님에 대한 소식은 저도 주교님께 전해 들었습니다.","JPN":"バーミンガム教授の件は、私も司教から聞きました。","ENG":"I heard the news from the bishop, regarding Professor Birmingham.","TWN":"伯明罕教授的消息我也聽主教說了。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그래. 마지막으로 편지가 왔던 그 날 이후로 행방이 묘연해지셨더군.","JPN":"ああ。最後の手紙が届いて以来、消息を絶たれたらしい。","ENG":"Yes. He has gone missing since the last letter arrived.","TWN":"嗯，收到信的那天之後就下落不明了。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};